import { Component, OnInit } from '@angular/core';
import { ActivatedRoute, Router } from '@angular/router';
import { MaintenanceItem } from '../../core/data.models';
import { MaintenanceService } from '../../services/maintenance.service';

@Component({
  selector: 'app-maintenance-detail',
  templateUrl: './maintenance-detail.component.html'
})
export class MaintenanceDetailComponent implements OnInit {
  item?: MaintenanceItem;

  constructor(private route: ActivatedRoute, private router: Router, private svc: MaintenanceService) {}

  ngOnInit(): void {
    const id = this.route.snapshot.paramMap.get('id');
    if (!id) return;
    this.svc.list$.subscribe(list => {
      this.item = list.find(i => i.id === id);
      if (!this.item) this.router.navigate(['/maintenance']);
    });
  }
}
<div *ngIf="item" class="card">
  <h2>{{item.title}}</h2>
  <div class="small">Status: {{item.status}}</div>
  <div style="margin-top:8px">Description: {{item.description || '—'}}</div>
  <div style="margin-top:8px">Next Due: {{item.nextDue || '—'}}</div>
  <div style="margin-top:8px">Recurrence: {{item.recurrence || '—'}}</div>
  <div style="margin-top:8px">Assigned to: {{item.assignedTo || '—'}}</div>
  <div style="margin-top:12px">
    <a [routerLink]="[item.id, 'edit']">Edit</a>
    <a routerLink="/maintenance" style="margin-left:8px">Back</a>
  </div>
</div>
